{"command":"$ErrorActionPreference = 'Stop'
$repos = Get-ChildItem -Directory | Where-Object { Test-Path (Join-Path $_.FullName '.git') }
foreach ($repo in $repos) {
  Write-Output "==== $($repo.Name) ===="
  git -C $repo.FullName fetch origin develop sandbox-albert
  $branch = git -C $repo.FullName branch --show-current
  if ($branch -ne 'sandbox-albert') { throw "$($repo.Name) is on $branch, expected sandbox-albert" }

  $dirty = git -C $repo.FullName status --porcelain
  $stashMade = $false
  if ($dirty) {
    git -C $repo.FullName stash push -u -m "codex temporary stash before syncing develop into sandbox-albert"
    $stashMade = $true
  }

  try {
    git -C $repo.FullName merge origin/develop --no-edit
    git -C $repo.FullName push origin sandbox-albert
    git -C $repo.FullName pull --ff-only origin sandbox-albert
  }
  catch {
    git -C $repo.FullName merge --abort 2>$null
    if ($stashMade) {
      git -C $repo.FullName stash pop
    }
    throw
  }

  if ($stashMade) {
    git -C $repo.FullName stash pop
  }
}
","workdir":"D:\repos\dflow","timeout_ms":120000}

