import { describe, expect, test } from '@jest/globals';
import {
  RFQ_ACTIVE_REQUIRES_TECH_PACK_MESSAGE,
  canChangeRfqStatusToActive,
  hasRfqTechPackLink,
  isRfqActiveStatus,
  isUserExemptFromTechPackRequirementForActive,
} from './rfq-status-validation';

describe('rfq-status-validation', () => {
  describe('isRfqActiveStatus', () => {
    test('returns true for Active title object', () => {
      expect(isRfqActiveStatus({ title: 'Active', id: 1 })).toBe(true);
    });

    test('returns true for Active id even without title', () => {
      expect(isRfqActiveStatus({ id: 1 })).toBe(true);
    });

    test('returns true for Active string', () => {
      expect(isRfqActiveStatus('Active')).toBe(true);
    });

    test('returns false for Draft', () => {
      expect(isRfqActiveStatus({ title: 'Draft', id: 3 })).toBe(false);
    });

    test('returns false for Inactive', () => {
      expect(isRfqActiveStatus({ title: 'Inactive', id: 2 })).toBe(false);
    });
  });

  describe('hasRfqTechPackLink', () => {
    test('returns true when Tech Pack Link is a non-empty URL', () => {
      expect(
        hasRfqTechPackLink({ 'Tech Pack Link': 'https://example.com/techpack.pdf' })
      ).toBe(true);
    });

    test('returns false when Tech Pack Link is null', () => {
      expect(hasRfqTechPackLink({ 'Tech Pack Link': null })).toBe(false);
    });

    test('returns false when Tech Pack Link is undefined', () => {
      expect(hasRfqTechPackLink({})).toBe(false);
    });

    test('returns false when Tech Pack Link is empty string', () => {
      expect(hasRfqTechPackLink({ 'Tech Pack Link': '' })).toBe(false);
    });

    test('returns false when Tech Pack Link is whitespace only', () => {
      expect(hasRfqTechPackLink({ 'Tech Pack Link': '   ' })).toBe(false);
    });

    test('returns false when Tech Pack Link is the string "null"', () => {
      expect(hasRfqTechPackLink({ 'Tech Pack Link': 'null' })).toBe(false);
    });
  });

  describe('isUserExemptFromTechPackRequirementForActive', () => {
    test('returns true for allow-listed user ids', () => {
      expect(isUserExemptFromTechPackRequirementForActive(17, [17, 62, 50])).toBe(true);
      expect(isUserExemptFromTechPackRequirementForActive(62, [17, 62, 50])).toBe(true);
    });

    test('returns false for user not on allow-list', () => {
      expect(isUserExemptFromTechPackRequirementForActive(21, [17, 62, 50])).toBe(false);
    });

    test('returns false when user id is null', () => {
      expect(isUserExemptFromTechPackRequirementForActive(null, [17, 62, 50])).toBe(false);
    });
  });

  describe('canChangeRfqStatusToActive', () => {
    test('allows Draft to Active when tech pack link exists', () => {
      expect(
        canChangeRfqStatusToActive(
          { 'Tech Pack Link': 'https://example.com/tp.pdf' },
          { title: 'Active', id: 1 }
        )
      ).toEqual({ allowed: true });
    });

    test('allows Inactive to Active when tech pack link exists', () => {
      expect(
        canChangeRfqStatusToActive(
          { Status: { title: 'Inactive', id: 2 }, 'Tech Pack Link': 'https://x.com/tp' },
          { title: 'Active', id: 1 }
        )
      ).toEqual({ allowed: true });
    });

    test('blocks Draft to Active when tech pack link is missing', () => {
      expect(
        canChangeRfqStatusToActive(
          { Status: { title: 'Draft', id: 3 }, 'Tech Pack Link': null },
          { title: 'Active', id: 1 }
        )
      ).toEqual({
        allowed: false,
        message: RFQ_ACTIVE_REQUIRES_TECH_PACK_MESSAGE,
      });
    });

    test('blocks Inactive to Active when tech pack link is null string', () => {
      expect(
        canChangeRfqStatusToActive(
          { 'Tech Pack Link': 'null' },
          { title: 'Active', id: 1 }
        )
      ).toEqual({
        allowed: false,
        message: RFQ_ACTIVE_REQUIRES_TECH_PACK_MESSAGE,
      });
    });

    test('allows changing to Draft without tech pack', () => {
      expect(
        canChangeRfqStatusToActive(
          { 'Tech Pack Link': null },
          { title: 'Draft', id: 3 }
        )
      ).toEqual({ allowed: true });
    });

    test('allows changing to Inactive without tech pack', () => {
      expect(
        canChangeRfqStatusToActive(
          { 'Tech Pack Link': null },
          { title: 'Inactive', id: 2 }
        )
      ).toEqual({ allowed: true });
    });

    test('allows staying on Active when tech pack already exists', () => {
      expect(
        canChangeRfqStatusToActive(
          { 'Tech Pack Link': 'https://example.com/tp.pdf' },
          { title: 'Active', id: 1 }
        )
      ).toEqual({ allowed: true });
    });

    test('allows Draft to Active without tech pack for exempt user', () => {
      expect(
        canChangeRfqStatusToActive(
          { Status: { title: 'Draft', id: 3 }, 'Tech Pack Link': null },
          { title: 'Active', id: 1 },
          'Tech Pack Link',
          { exemptUserIds: [17, 62, 50], currentUserId: 17 }
        )
      ).toEqual({ allowed: true });
    });

    test('still blocks non-exempt user without tech pack', () => {
      expect(
        canChangeRfqStatusToActive(
          { Status: { title: 'Draft', id: 3 }, 'Tech Pack Link': null },
          { title: 'Active', id: 1 },
          'Tech Pack Link',
          { exemptUserIds: [17, 62, 50], currentUserId: 21 }
        )
      ).toEqual({
        allowed: false,
        message: RFQ_ACTIVE_REQUIRES_TECH_PACK_MESSAGE,
      });
    });
  });
});

