/**
 * Blocks "Copy to new product" when RFQ product Type / Sub-Type / Sub-Sub-Type
 * merchGroup rows are missing or inactive (legacy RFQs before May 2025).
 */

const COPY_BLOCKED_MESSAGE =
  "RFQs created before May 2025 can't be copied";

const PRODUCT_TYPE_KEYS = ['Material', 'Product Type'];
const PRODUCT_SUB_TYPE_KEYS = ['Construction', 'Product Sub-Type'];
const PRODUCT_SUB_SUB_TYPE_KEYS = ['Treatment', 'Product Sub-Sub-Type'];

/**
 * @param {unknown} value - grid cell or raw id
 * @returns {number|null}
 */
function parseMerchGroupId(value) {
  if (value == null || value === '') {
    return null;
  }
  if (typeof value === 'number' && !Number.isNaN(value)) {
    return value;
  }
  if (typeof value === 'object' && value.id != null && value.id !== '') {
    const id = parseInt(value.id, 10);
    return Number.isNaN(id) ? null : id;
  }
  const parsed = parseInt(String(value), 10);
  return Number.isNaN(parsed) ? null : parsed;
}

/**
 * @param {object} row - RFQ grid row or API payload
 */
function extractMerchGroupIdsFromRfqRow(row) {
  if (!row || typeof row !== 'object') {
    return {
      productTypeId: null,
      productSubTypeId: null,
      productSubSubTypeId: null,
    };
  }

  const pick = (keys) => {
    for (const key of keys) {
      const id = parseMerchGroupId(row[key]);
      if (id != null) {
        return id;
      }
    }
    return null;
  };

  return {
    productTypeId:
      pick(PRODUCT_TYPE_KEYS) ?? parseMerchGroupId(row.rfqItem_udf2),
    productSubTypeId:
      pick(PRODUCT_SUB_TYPE_KEYS) ?? parseMerchGroupId(row.rfqItem_udf4),
    productSubSubTypeId:
      pick(PRODUCT_SUB_SUB_TYPE_KEYS) ?? parseMerchGroupId(row.rfqItem_udf3),
  };
}

/**
 * @param {object|null|undefined} record - merchGroup row or Sequelize instance
 */
function isMerchGroupActive(record) {
  if (!record) {
    return false;
  }
  const data = record.dataValues || record;
  return data.is_active === true;
}

/**
 * Pure eligibility check (unit tests).
 *
 * @param {{ productTypeId: number|null, productSubTypeId: number|null, productSubSubTypeId: number|null }} ids
 * @param {Map<number, object>|Record<number, object>} recordsById
 */
function evaluateRfqCopyMerchGroupEligibility(ids, recordsById) {
  const lookup =
    recordsById instanceof Map
      ? (id) => recordsById.get(id)
      : (id) => recordsById[id];

  const required = [
    { key: 'productTypeId', label: 'Product Type' },
    { key: 'productSubTypeId', label: 'Product Sub-Type' },
    { key: 'productSubSubTypeId', label: 'Product Sub-Sub-Type' },
  ];

  const inactiveLabels = [];

  for (const { key, label } of required) {
    const id = ids[key];
    if (id == null) {
      return {
        allowed: false,
        message: COPY_BLOCKED_MESSAGE,
        reason: 'missing_merch_group_id',
        inactiveLabels: [label],
      };
    }
    const record = lookup(id);
    if (!isMerchGroupActive(record)) {
      inactiveLabels.push(label);
    }
  }

  if (inactiveLabels.length > 0) {
    return {
      allowed: false,
      message: COPY_BLOCKED_MESSAGE,
      reason: 'inactive_or_missing_merch_group',
      inactiveLabels,
    };
  }

  return {
    allowed: true,
    message: null,
    reason: null,
    inactiveLabels: [],
  };
}

/**
 * @param {object} models - Sequelize models (needs merchGroup)
 * @param {{ productTypeId: number|null, productSubTypeId: number|null, productSubSubTypeId: number|null }} ids
 */
async function loadMerchGroupRecords(models, ids) {
  const uniqueIds = [
    ids.productTypeId,
    ids.productSubTypeId,
    ids.productSubSubTypeId,
  ].filter((id) => id != null);

  const rows = await models.merchGroup.findAll({
    where: { mg_id: uniqueIds },
  });

  const map = new Map();
  for (const row of rows) {
    const data = row.dataValues || row;
    map.set(data.mg_id, data);
  }
  return map;
}

/**
 * @param {object} models
 * @param {{ productTypeId, productSubTypeId, productSubSubTypeId }} ids
 */
async function checkMerchGroupIdsForRfqCopy(models, ids) {
  const recordsById = await loadMerchGroupRecords(models, ids);
  return evaluateRfqCopyMerchGroupEligibility(ids, recordsById);
}

/**
 * @param {object} remapRFQData - output of mapRFQItem (new row payload)
 */
function extractMerchGroupIdsFromRemapPayload(remapRFQData) {
  if (!remapRFQData || typeof remapRFQData !== 'object') {
    return {
      productTypeId: null,
      productSubTypeId: null,
      productSubSubTypeId: null,
    };
  }
  return {
    productTypeId: parseMerchGroupId(remapRFQData.rfqItem_udf2),
    productSubTypeId: parseMerchGroupId(remapRFQData.rfqItem_udf4),
    productSubSubTypeId: parseMerchGroupId(remapRFQData.rfqItem_udf3),
  };
}

/**
 * Validates merch groups on the item being created (user-selected types for "Change all fields").
 * @param {object} models
 * @param {object} remapRFQData
 */
async function validateRfqCopyPayload(models, remapRFQData) {
  const ids = extractMerchGroupIdsFromRemapPayload(remapRFQData);
  return checkMerchGroupIdsForRfqCopy(models, ids);
}

/**
 * @param {object} models
 * @param {number} rfqItemId
 */
async function validateRfqCopyByRfqItemId(models, rfqItemId) {
  const item = await models.RFQItem.findOne({
    where: { rfqItem_id: rfqItemId },
    attributes: ['rfqItem_id', 'rfqItem_udf2', 'rfqItem_udf3', 'rfqItem_udf4'],
  });

  if (!item) {
    return {
      allowed: false,
      message: 'RFQ item not found.',
      reason: 'rfq_not_found',
      inactiveLabels: [],
    };
  }

  const data = item.dataValues || item;
  return checkMerchGroupIdsForRfqCopy(models, {
    productTypeId: data.rfqItem_udf2 ?? null,
    productSubTypeId: data.rfqItem_udf4 ?? null,
    productSubSubTypeId: data.rfqItem_udf3 ?? null,
  });
}

/**
 * @param {object} models
 * @param {object} [options]
 * @param {number} [options.rfqItemId]
 * @param {object} [options.row] - grid row payload
 */
async function validateRfqCopyAllowed(models, options = {}) {
  if (options.row) {
    const ids = extractMerchGroupIdsFromRfqRow(options.row);
    return checkMerchGroupIdsForRfqCopy(models, ids);
  }

  const rfqItemId = parseInt(options.rfqItemId, 10);
  if (!rfqItemId || Number.isNaN(rfqItemId)) {
    return {
      allowed: false,
      message: 'rfqItem_id is required',
      reason: 'invalid_request',
      inactiveLabels: [],
    };
  }

  return validateRfqCopyByRfqItemId(models, rfqItemId);
}

