import { itemService } from './services/main.service';
import { MatSnackBar } from '@angular/material/snack-bar';

export const RFQ_COPY_BLOCKED_MESSAGE =
  "RFQs created before May 2025 can't be copied";

/**
 * Returns true when copy is allowed; shows snackbar and returns false when blocked.
 */
export async function ensureRfqCopyAllowed(
  rowData: { id?: number; [key: string]: unknown },
  itemSvc: itemService = window['itemService'],
  snackBar: MatSnackBar = window['_snackBar']
): Promise<boolean> {
  if (!rowData) {
    snackBar?.open('Unable to verify copy eligibility.', 'Close');
    return false;
  }

  try {
    const res: any = await itemSvc
      .checkRfqCopyAllowed({
        rfqItem_id: rowData.id,
        row: rowData,
      })
      .toPromise();

    if (res?.allowed === true) {
      return true;
    }

    snackBar?.open(res?.message || RFQ_COPY_BLOCKED_MESSAGE, 'Close', {
      duration: 6000,
    });
    return false;
  } catch {
    snackBar?.open('Unable to verify copy eligibility.', 'Close');
    return false;
  }
}

