  getLicenseString(data) {
    if (!data) return '';
    let licenceTextValue = "";
    if (data.title == null) {
      // Array of license objects
      if (!Array.isArray(data) || data.length === 0) return '';
      for (var i = 0; data.length > i; i++) {
        if (i != data.length - 1) {
          licenceTextValue = data[i].title + "," + licenceTextValue
        } else {
          licenceTextValue = licenceTextValue + data[i].title
        }
      }
      return licenceTextValue;
    } else {
      return data.title
    }
  }
  getDivisionString(data: any): string {
    if (!data) return '';
    if (Array.isArray(data)) {
      if (!data.length) return '';
      if (data[0]?.divCode_code != undefined) {
        return data.map((d: any) => d.divCode_code).filter(Boolean).join(',');
      }
    }
    if (data.divCode_code) return data.divCode_code;
    if (data.title != undefined) return data.title;
    return String(data);
  }

  async onPriceCodeChange(element, value) {
    if (this.STDImport == false) {
      if (value) {
        if (element === 'material') {
          this.priceCode[0] = value.mg_code || ''
        } else if (element === 'construction') {
          this.priceCode[1] = value.mg_code || ''
        } else if (element === 'treatment') {
          this.priceCode[2] = value.mg_code || ''
        } else if (element === 'size') {
          this.priceCode[3] = value.mg_code || ''
        } else if (element === 'depth') {
          this.priceCode[6] = value.code || ''
        } else if ( element === 'customer' &&(this.data.option === 1 || this.data.option === 2)) {
          this.priceCode[8] = value.code || '';
        } else if ( element === 'license' && (this.data.option === 1 || this.data.option === 2)) {
          this.priceCode[9] = value.mg_code || '';
        }
        this.priceCodeValue = '';
        for (let i = 0; i < this.priceCode.length; i++) {
          this.priceCodeValue += this.priceCode[i] || '';
        }
      }
    }
  }

  async handleItemSelection(itemInfo: any): Promise<void> {
    const itemData = itemInfo[0];
