    if (division) {
      await this.onDivisionChange(division);
    }

    const selectedMaterial = this.material.find(material => material.mg_code === itemData.udf_merchgroup01);
    if (selectedMaterial?.mgCategory) {
      const category = this.mgCategories.find(c => c.mgCategory === selectedMaterial.mgCategory);
      if (category) {
        this.onCategoryChange(category);
      }
    }

    if (selectedMaterial) {
      this.productTypeControler.setValue(selectedMaterial);
      this.onPriceCodeChange('material', selectedMaterial);
      this.getProductSubTypeByProductType(selectedMaterial);
    }

    const selectedConstruction = this.construction.find(construction => construction.mg_code === itemData.udf_merchgroup02);
    if (selectedConstruction) {
      this.productSubTypeControler.setValue(selectedConstruction);
      this.onPriceCodeChange('construction', selectedConstruction);
      this.getProductSubSubTypeByProductSubType(selectedConstruction);
    }

    const selectedTreatment = this.treatment.find(treatment => treatment.mg_code === itemData.udf_merchgroup03);
    if (selectedTreatment) {
      this.productSubSubTypeControler.setValue(selectedTreatment);
      this.onPriceCodeChange('treatment', selectedTreatment);
    }

    // License

