  private getMerchGroupDivisionCodes(): number[] {
    const selected = this.dialogData?.selectedDivisionCode;
    if (!selected) {
      return [];
    }
    const divisions = Array.isArray(selected) ? selected : [selected];
    return divisions
      .map((d: any) => d?.divCode_id)
      .filter((id: number) => id != null && id !== undefined);
  }

  private getSelectedDivisionTitle(): string {
    const selected = this.dialogData?.selectedDivisionCode;
    if (!selected) {
      return '';
    }
    const divisions = Array.isArray(selected) ? selected : [selected];
    return divisions
      .map((d: any) => d?.division_name || d?.divCode_code || '')
      .filter(Boolean)
      .join(',');
  }

  private getLicenseTitles(license: any): string[] {
    if (!license) {
      return [];
    }
    if (typeof license === 'string') {
      return license.split(',').map((t: string) => t.trim()).filter(Boolean);
    }
    if (Array.isArray(license)) {
      return license.map((x: any) => x?.title).filter(Boolean);
    }
    if (license.title) {
      return license.title.split(',').map((t: string) => t.trim()).filter(Boolean);
    }
    return [];
  }

  private getRowMerchValue(row: any, canonical: 'Material' | 'Construction' | 'Treatment'): any {
    const aliases: Record<string, string[]> = {
      Material: ['Material', 'Product Type'],
      Construction: ['Construction', 'Product Sub-Type'],
      Treatment: ['Treatment', 'Product Sub-Sub-Type'],
    };
    for (const key of aliases[canonical]) {
      if (row[key]) {
        return row[key];
      }
    }
    return null;
  }

  private normalizeDivisionTitle(title: string): string {
    return title.trim().toLowerCase();
  }

  private isSpruceNonLicLabel(title: string): boolean {
    const t = this.normalizeDivisionTitle(title);
    return (
      t === 'spruce non-lic' ||
      t === 'snl' ||
      (t.includes('spruce') && t.includes('non'))
    );
  }

  private resolveDivisionCodeIdFromTitle(title: string): number | null {
    if (!title) {
      return null;
    }
    if (this.isSpruceNonLicLabel(title)) {
      return SPRUCE_NON_LIC_DIV_CODE_ID;
    }
    const normalized = this.normalizeDivisionTitle(title);
    const selected = this.dialogData?.selectedDivisionCode;
    const divisions = Array.isArray(selected) ? selected : selected ? [selected] : [];
    for (const d of divisions) {
      const labels = [d?.division_name, d?.divCode_code]
        .filter(Boolean)
        .map((label: string) => this.normalizeDivisionTitle(label));
      if (labels.some((label) => label === normalized)) {
        return d.divCode_id ?? null;
      }
    }
    return null;
  }

  private getRowDivisionCodeId(row: any): number | null {
    const rowDiv = row['Div'];
    if (Array.isArray(rowDiv)) {
      for (const entry of rowDiv) {
        if (entry?.divCode_id != null) {
          return entry.divCode_id;
        }
        if (entry?.id != null) {
          return entry.id;
        }
        const fromTitle = this.resolveDivisionCodeIdFromTitle(entry?.title || '');
        if (fromTitle != null) {
          return fromTitle;
        }
      }
      return null;
    }
    if (rowDiv?.divCode_id != null) {
      return rowDiv.divCode_id;
    }
    if (rowDiv?.id != null) {
      return rowDiv.id;
    }
    const title = rowDiv?.title || (typeof rowDiv === 'string' ? rowDiv : '');
    const fromTitle = this.resolveDivisionCodeIdFromTitle(title);
    if (fromTitle != null) {
      return fromTitle;
    }
    const codes = this.getMerchGroupDivisionCodes();
    if (codes.length === 1) {
      return codes[0];
    }
    return null;
  }

  private enrichRowDivision(row: any): void {
    const rowDiv = row['Div'];
    if (!rowDiv || Array.isArray(rowDiv)) {
      return;
    }
    if (rowDiv.divCode_id != null || rowDiv.id != null) {
      return;
    }
    const title = rowDiv.title || (typeof rowDiv === 'string' ? rowDiv : '');
    const resolved = this.resolveDivisionCodeIdFromTitle(title);
    if (resolved != null) {
      row['Div'] =
        typeof rowDiv === 'object'
          ? { ...rowDiv, title: rowDiv.title || title, divCode_id: resolved, id: resolved }
          : { title, divCode_id: resolved, id: resolved };
    }
  }

  private isLicenseRequiredForRow(row: any): boolean {
    const divId = this.getRowDivisionCodeId(row);
    if (divId === SPRUCE_NON_LIC_DIV_CODE_ID) {
      return false;
    }
    const codes = this.getMerchGroupDivisionCodes();
    if (codes.length && codes.every((id) => id === SPRUCE_NON_LIC_DIV_CODE_ID)) {
      return false;
    }
    return true;
  }

  private getDivTitle(row: any): string {
    const rowDiv = row['Div'];
    if (Array.isArray(rowDiv)) {
      return rowDiv.map((d: any) => d?.title).filter(Boolean).join(', ');
    }
    if (rowDiv?.title) {
      return rowDiv.title;
    }
    if (typeof rowDiv === 'string') {
      return rowDiv;
    }
    return '';
  }

  private normalizeRowForSave(row: any): void {
    this.enrichRowDivision(row);
    const material = this.getRowMerchValue(row, 'Material');
    const construction = this.getRowMerchValue(row, 'Construction');
    const treatment = this.getRowMerchValue(row, 'Treatment');
    if (material) {
      row['Material'] = material;
      row['Product Type'] = material;
    }
    if (construction) {
      row['Construction'] = construction;
      row['Product Sub-Type'] = construction;
    }
    if (treatment) {
      row['Treatment'] = treatment;
      row['Product Sub-Sub-Type'] = treatment;
    }
    if (!row['Div']?.title) {
      const divisionTitle = this.getSelectedDivisionTitle();
      if (divisionTitle) {
        const codes = this.getMerchGroupDivisionCodes();
        row['Div'] = {
          title: divisionTitle,
          ...(codes.length === 1 ? { divCode_id: codes[0], id: codes[0] } : {}),
        };
      }
    }
    if (!this.isLicenseRequiredForRow(row) && !this.getLicenseTitles(row['License']).length) {
      row['License'] = { title: '' };
    }
  }

  private getMissingRequiredFields(row: any): string[] {
    const missing: string[] = [];
    if (this.isLicenseRequiredForRow(row) && !this.getLicenseTitles(row['License']).length) {
      missing.push('License');
    }
    if (!this.getRowMerchValue(row, 'Treatment')) {
      missing.push('Product Sub-Sub-Type');
    }
    if (!this.getRowMerchValue(row, 'Construction')) {
      missing.push('Product Sub-Type');
    }
    if (!row['Depth']) {
      missing.push('Depth');
    }
    if (!row['Size (LxW)']) {
      missing.push('Size (LxW)');
