  async onSave() {
    const divisionCodes = this.getMerchGroupDivisionCodes();
    if (!divisionCodes.length) {
      this._snackBar.open('Please select a division before saving.', 'Close');
      return;
    }
    let licenseOptions = [];
    let verifiedData = 0;
    try {
      const data: any = await firstValueFrom(
        this.itemService.getMerchGroup({ divisionCode: divisionCodes })
      );
      for (var i = 0; data.length > i; i++) {
        for (var j = 0; data[i].merchGroupHeaders.length > j; j++) {
          if (data[i].merchGroupHeaders[j].mgTypeDesc == 'Licensor') {
            for (var k = 0; data[i].merchGroupHeaders[j].merchGroups.length > k; k++) {
              licenseOptions.push({
                title: data[i].merchGroupHeaders[j].merchGroups[k].mg_desc,
                id: data[i].merchGroupHeaders[j].merchGroups[k].mg_id,
                mg_code: data[i].merchGroupHeaders[j].merchGroups[k].mg_code,
              });
            }
          }
        }
      }
      const allMissing: string[] = [];
      for (var i = 0; i < this.data.length; i++) {
        this.normalizeRowForSave(this.data[i]);
        const missing = this.getMissingRequiredFields(this.data[i]);
        if (missing.length) {
          allMissing.push(...missing);
          continue;
        }
        const licenses = this.getLicenseTitles(this.data[i]['License']);
        if (!this.data[i]['Date Modified']) {
          this.data[i]['Date Modified'] = formatDate(new Date(), 'MM/dd/yyyy', 'en-US');
        }
        let highestRoyalty = 0;
        let fobHighestRoyalty = 0;
        for (var j = 0; licenses.length > j; j++) {
          for (var k = 0; licenseOptions.length > k; k++) {
            if (licenses[j] == licenseOptions[k].title) {
              if (licenseOptions[k].fob_royalty_rate > highestRoyalty) {
                fobHighestRoyalty = licenseOptions[k].fob_royalty_rate;
                highestRoyalty = licenseOptions[k].royalty_rate;
              }
            }
          }
        }
        this.data[i][this.getMasterFiledName('lic_fob_royalty')] = fobHighestRoyalty;
        this.data[i][this.getMasterFiledName('lic_whse_royalty')] = highestRoyalty;
        this.data[i][this.getMasterFiledName('lic_poe_royalty')] = highestRoyalty;
        this.data[i][this.getMasterFiledName('lic_mddp_royalty')] = highestRoyalty;
        this.data[i]['Gen FOB Royalty %'] = 0;
        this.data[i]['Gen POE Royalty %'] = 0;
        this.data[i]['Gen MDDP Royalty %'] = 0;
        this.data[i]['Gen Whse Royalty %'] = 0;
        this.data[i]['royalty'] = highestRoyalty;
        this.data[i]['rfq_container_id_fk'] = this.latest_rfq_container_id;
        verifiedData++;
      }
      if (this.data.length == verifiedData) {
        this.dialogRef.close(this.data);
      } else {
        const uniqueMissing = [...new Set(allMissing)];
        this._snackBar.open(
          `Please fill all required fields. Missing: ${uniqueMissing.join(', ')}.`,
          'Close'
        );
      }
    } catch (err) {
      console.error('[AddNewProductGrid] getMerchGroup failed:', err);
    }
  }

  onDelete() {
    let selectedRows = this.params.api.getSelectedNodes()
    let oldData = this.data
    for (var i = 0; this.data.length > i; i++) {
      for (var j = 0; selectedRows.length > j; j++) {
        if (oldData[i]['Price Code'] == selectedRows[j].data['Price Code']) {
          this.params.api.applyTransaction({ remove: [oldData[i]] });
          oldData.splice(i, 1);
        }
      }
    }
    this.data = oldData
  }

