Customer.selectedVendor = async (req, result) => {
  try {
    const mappedItem = await utility.mapRFQItem(req.body);
    const rfqItemId = mappedItem.rfqItem_id || mappedItem.rfq_item_id;
    const condition = rfqItemId
      ? { rfqItem_id: rfqItemId }
      : { rfqItem_style_number: mappedItem.rfqItem_style_number };

    const rfqItem = await sql.RFQItem.findOne({ where: condition });
    if (!rfqItem) {
      return result(null, { message: 'RFQ Item not found' });
    }

    await rfqItem.update(mappedItem);
    result(null, mappedItem);
  } catch (err) {
    result(err, null);
  }
}


