import { Component, OnInit, Inject } from '@angular/core';
import { MatDialogRef, MAT_DIALOG_DATA } from '@angular/material/dialog';
import { MatSnackBar } from '@angular/material/snack-bar';
import { itemService } from '../../../helpers/services/main.service';
import { firstValueFrom } from 'rxjs';

type DialogStage = 'form' | 'uploading' | 'result';

interface ImportResult {
  created: number;
  items: { priceCode: string; description: string }[];
  errors: string[];
  groupId: number;
  groupName: string;
}

@Component({
  selector: 'app-factory-bulk-upload-dialog',
  templateUrl: './factory-bulk-upload-dialog.component.html',
  styleUrls: ['./factory-bulk-upload-dialog.component.scss'],
  standalone: false,
})
export class FactoryBulkUploadDialogComponent implements OnInit {
  stage: DialogStage = 'form';

  /** Group name field — pre-filled with the factory's name from the token. */
  groupName: string = '';

  /** The xlsx file the factory selects to upload. */
  selectedFile: File | null = null;

  /** Drag-over state for the drop zone. */
  isDragOver = false;

  /** Result after a successful import. */
  importResult: ImportResult | null = null;

  /** Error message if the import call itself fails. */
  topLevelError: string | null = null;

  constructor(
    public dialogRef: MatDialogRef<FactoryBulkUploadDialogComponent>,
    @Inject(MAT_DIALOG_DATA) public data: { vendorName?: string },
    private itemService: itemService,
    private snackBar: MatSnackBar,
  ) {}

  ngOnInit(): void {
    // Pre-fill the group name with the factory's name so they only need to append details.
    const name = this.data?.vendorName || '';
    this.groupName = name;
  }

  // ── Template download ──────────────────────────────────────────────────────

  async downloadTemplate(): Promise<void> {
    try {
      const blob = await firstValueFrom(this.itemService.getRFQFactoryTemplate());
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `${(this.data?.vendorName || 'Factory').replace(/\s+/g, '_')}_Offer_Template.xlsx`;
      a.click();
      URL.revokeObjectURL(url);
    } catch (err) {
      this.snackBar.open('Failed to download template. Please try again.', 'Dismiss', { duration: 4000 });
    }
  }

  // ── File selection ─────────────────────────────────────────────────────────

  onFileInputChange(event: Event): void {
    const input = event.target as HTMLInputElement;
    if (input.files && input.files.length > 0) {
      this.setFile(input.files[0]);
    }
  }

  onDragOver(event: DragEvent): void {
    event.preventDefault();
    event.stopPropagation();
    this.isDragOver = true;
  }

  onDragLeave(event: DragEvent): void {
    event.preventDefault();
    event.stopPropagation();
    this.isDragOver = false;
  }

  onDrop(event: DragEvent): void {
    event.preventDefault();
    event.stopPropagation();
    this.isDragOver = false;
    const files = event.dataTransfer?.files;
    if (files && files.length > 0) {
      this.setFile(files[0]);
    }
  }

  private setFile(file: File): void {
    const allowed = [
      'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
      'application/vnd.ms-excel',
    ];
