    this.selectedFile = file;
  }

  clearFile(): void {
    this.selectedFile = null;
  }

  // ── Upload ─────────────────────────────────────────────────────────────────

  get canUpload(): boolean {
    return !!(this.selectedFile && this.groupName.trim());
  }

  async upload(): Promise<void> {
    if (!this.canUpload) return;
    this.stage = 'uploading';
    this.topLevelError = null;

    const formData = new FormData();
    formData.append('file', this.selectedFile!, this.selectedFile!.name);
    formData.append('groupName', this.groupName.trim());

    try {
      const result = await firstValueFrom(this.itemService.importFactoryRFQ(formData));
      this.importResult = result;
      this.stage = 'result';
    } catch (err: any) {
      this.topLevelError =
        err?.error?.message || err?.message || 'Upload failed. Please try again.';
      this.stage = 'form';
    }
  }

  // ── Helpers ────────────────────────────────────────────────────────────────

  get hasErrors(): boolean {
    return !!(this.importResult?.errors && this.importResult.errors.length > 0);
  }

  close(): void {
    this.dialogRef.close(
      this.importResult?.created ? { refresh: true } : null
    );
  }
}

